require\('dotenv'\).config\(\);
const { createClient } = require\('@supabase/supabase-js'\);
\(async \(\) => {
  const svc = createClient\(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_KEY\);

  // Find the test user
  const { data: { users } } = await svc.auth.admin.listUsers\(\);
  const testUser = users.find\(u => u.email === 'pmgps-test-e2e@test.example.com'\);
  if \(!testUser\) { console.log\('User not found'\); return; }

  // Update app_metadata to set provider to 'google' 
  const { data, error } = await svc.auth.admin.updateUserById\(testUser.id, {
    app_metadata: { provider: 'google', providers: ['google'] },
  }\);
  if \(error\) { console.error\('Error:', error.message\); return; }
  console.log\('Updated provider to google:', data.user.app_metadata\);
}\)\(\);
" 2>&1)
